Can you write me a C program using the following stack structure: 
struct int_node {
    int value;
    struct int_node *next;
};
and create a simple calculator that can add two arbitrary size integers entered from the command line.

Certainly! Below is a simple C program that defines a stack structure for integers (`struct int_node`), allows push and pop operations on the stack, and uses the stack to perform addition of two arbitrarily large integers entered as strings from the command line.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct int_node {
    int value;
    struct int_node *next;
};

// Push an element onto the stack
void push(struct int_node** top, int value) {
    struct int_node* new_node = (struct int_node*)malloc(sizeof(struct int_node));
    new_node->value = value;
    new_node->next = *top;
    *top = new_node;
}

// Pop an element from the stack
int pop(struct int_node** top) {
    if (*top == NULL) {
        printf("Stack is empty\n");
        return -1;
    }
    struct int_node* temp = *top;
    int poppedValue = temp->value;
    *top = (*top)->next;
    free(temp);
    return poppedValue;
}

// Add two numbers represented by stacks and return the sum as a stack
struct int_node* add(struct int_node* num1, struct int_node* num2) {
    struct int_node* sumStack = NULL;
    int carry = 0;

    while (num1 != NULL || num2 != NULL || carry != 0) {
        int sum = carry;
        if (num1 != NULL) {
            sum += num1->value;
            num1 = num1->next;
        }
        if (num2 != NULL) {
            sum += num2->value;
            num2 = num2->next;
        }
        carry = sum / 10;
        sum = sum % 10;
        push(&sumStack, sum);
    }
    return sumStack;
}

// Utility function to fill stack from a number string
void fillStack(struct int_node **stack, char *number) {
    for (int i = strlen(number) - 1; i >= 0; --i) {
        push(stack, number[i] - '0');
    }
}

// Utility function to print stack as number
void printStackAsNumber(struct int_node* stack) {
    if (stack == NULL)
        return;
    printStackAsNumber(stack->next);
    printf("%d", stack->value);
}

int main(int argc, char *argv[]) {
    if (argc != 3) {
        printf("Usage: %s <number1> <number2>\n", argv[0]);
        return 1;
    }

    struct int_node* num1 = NULL;
    struct int_node* num2 = NULL;

    fillStack(&num1, argv[1]);
    fillStack(&num2, argv[2]);

    struct int_node* result = add(num1, num2);

    printf("Sum: ");
    printStackAsNumber(result);
    printf("\n");

    // Free memory for all stacks
    while (num1 != NULL) pop(&num1);
    while (num2 != NULL) pop(&num2);
    while (result != NULL) pop(&result);

    return 0;
}
```

This program expects two arguments (the large numbers to add). It fills two stacks with the digits of these numbers, adds the numbers using the `add` function, and then prints the result.

