#include <stdlib.h>
#include <string.h>

struct int_node {
    int value;
    struct int_node *next;
};

void push(struct int_node** top, int value) {
    struct int_node* new_node = (struct int_node*)malloc(sizeof(struct int_node));
    if (!new_node) {
        fprintf(stderr, "Memory allocation error\n");
        exit(EXIT_FAILURE);
    }
    new_node->value = value;
    new_node->next = *top;
    *top = new_node;
}

int pop(struct int_node** top) {
    if (*top == NULL) {
        fprintf(stderr, "Stack underflow\n");
        exit(EXIT_FAILURE);
    }
    struct int_node* temp = *top;
    int poppedValue = temp->value;
    *top = (*top)->next;
    free(temp);
    return poppedValue;
}

// We iterate over the stacks representing the two numbers and sum each digit.
// We also keep track of the carry from the previous digit addition, if any.
struct int_node* add(struct int_node* num1, struct int_node* num2) {
    struct int_node* sumStack = NULL; // The stack to hold the result
    int carry = 0;                    // Initialize carry to zero

    // Loop until both stacks are empty or there is a carry
    while (num1 != NULL || num2 != NULL || carry != 0) {
        int val1 = (num1 != NULL) ? num1->value : 0;
        int val2 = (num2 != NULL) ? num2->value : 0;

        // Calculate the sum of the current digits and the carry
        int sum = val1 + val2 + carry;

        // Update carry for next iteration
        carry = sum / 10;

        // Push the single digit to the result stack
        push(&sumStack, sum % 10);

        // Move to the next digits
        if (num1 != NULL) num1 = num1->next;
        if (num2 != NULL) num2 = num2->next;
    }
    return sumStack; // Return the result sum as a stack
}

// Fill the stack with the digits of the input number (as a string)
void fillStack(struct int_node **stack, const char *number) {
    int length = strlen(number);
    for (int i = length - 1; i >= 0; --i) {
        if (number[i] < '0' || number[i] > '9') {
            fprintf(stderr, "Invalid character in number: %c\n", number[i]);
            exit(EXIT_FAILURE);
        }
        push(stack, number[i] - '0'); // Convert char to int and push
    }
}

// Recursive function to print the stack without altering it
void printStackAsNumber(const struct int_node* stack) {
    if (stack == NULL) return;
    printStackAsNumber(stack->next); // Go to the bottom of the stack
    printf("%d", stack->value);      // Print digits starting from least significant
}

int main(int argc, char *argv[]) {
    if (argc != 3) {
        fprintf(stderr, "Usage: %s <number1> <number2>\n", argv[0]);
        return EXIT_FAILURE;
    }

    struct int_node* num1 = NULL;
    struct int_node* num2 = NULL;

    fillStack(&num1, argv[1]);
    fillStack(&num2, argv[2]);

    struct int_node* result = add(num1, num2);

    printf("Sum: ");
    printStackAsNumber(result);
    printf("\n");

    // Free memory for all stacks
    while (num1 != NULL) pop(&num1);
    while (num2 != NULL) pop(&num2);
    while (result != NULL) pop(&result);

    return EXIT_SUCCESS;
}
```

