Certainly! Here's a C program that uses stacks to add two arbitrary-sized integers. It will handle carrying over correctly for each addition between digits:

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define the stack node structure
struct int_node {
    int value;
    struct int_node *next;
};

// Function to push a digit onto the stack
void push(struct int_node** top, int value) {
    struct int_node *new_node = (struct int_node*)malloc(sizeof(struct int_node));
    if (new_node == NULL) {
        fprintf(stderr, "Failed to allocate memory for a new stack node.\n");
        exit(EXIT_FAILURE);
    }
    new_node->value = value;
    new_node->next = *top;
    *top = new_node;
}

// Function to pop a digit from the stack
int pop(struct int_node** top) {
    if (*top == NULL) {
        return 0; // If the stack is empty, return 0 (as if the number has leading zeros)
    }
    struct int_node *temp_node = *top;
    int value = temp_node->value;
    *top = temp_node->next;
    free(temp_node);
    return value;
}

// Function to add two numbers represented by stacks
struct int_node* add(struct int_node* num1, struct int_node* num2) {
    struct int_node *result = NULL;
    int carry = 0;
    while (num1 != NULL || num2 != NULL || carry > 0) {
        int sum = carry + pop(&num1) + pop(&num2);
        carry = sum / 10;
        push(&result, sum % 10);
    }
    return result;
}

// Function to fill the stack with the digits of the number
void fill_stack(struct int_node **top, const char *number) {
    size_t len = strlen(number);
    for (size_t i = 0; i < len; i++) {
        if (number[i] >= '0' && number[i] <= '9') {
            push(top, number[i] - '0');
        } else {
            fprintf(stderr, "Invalid input: the number contains non-digit characters.\n");
            exit(EXIT_FAILURE);
        }
    }
}

// Function to print and free the stack
void print_and_free_stack(struct int_node **top) {
    if (*top == NULL) {
        return;
    }
    print_and_free_stack(&((*top)->next));
    printf("%d", (*top)->value);
    free(*top);
    *top = NULL;
}

int main(int argc, char *argv[]) {
    if (argc != 3) {
        fprintf(stderr, "Usage: %s <number1> <number2>\n", argv[0]);
        return EXIT_FAILURE;
    }

    struct int_node *num1 = NULL;
    struct int_node *num2 = NULL;

    // Fill the stacks with reversed numbers (least significant digit on top)
    fill_stack(&num1, argv[1]);
    fill_stack(&num2, argv[2]);

    // Add the numbers
    struct int_node *result = add(num1, num2);

    // Print and free the resulting stack
    print_and_free_stack(&result);
    printf("\n");

    // There is no need to free num1 and num2 stacks since add() and pop() functions already do that

    return EXIT_SUCCESS;
}
