#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct int_node {
    int value;
    struct int_node *next;
};

void push(struct int_node **head, int value) {
    struct int_node *new_node = (struct int_node *)malloc(sizeof(struct int_node));
    if (new_node == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        exit(EXIT_FAILURE);
    }
    new_node->value = value;
    new_node->next = *head;
    *head = new_node;
}

int pop(struct int_node **head) {
    if (*head == NULL) {
        return 0;
    }
    struct int_node *temp = *head;
    int result = temp->value;
    *head = temp->next;
    free(temp);
    return result;
}

// Iterative approach to print and free the stack
void print_and_free_stack(struct int_node **head) {
    // Reverse the stack first to print from the most significant digit
    struct int_node *reversed = NULL;
    while (*head) {
        int value = pop(head);
        push(&reversed, value);
    }

    // Print and free the reversed stack
    while (reversed) {
        printf("%d", reversed->value);
        pop(&reversed);
    }
}

