void add(struct int_node **result, struct int_node **stack1, struct int_node **stack2) {
    int carry = 0;
    while (*stack1 != NULL || *stack2 != NULL || carry > 0) {
        int value1 = *stack1 ? pop(stack1) : 0;
        int value2 = *stack2 ? pop(stack2) : 0;
        int sum = value1 + value2 + carry;
        carry = sum / 10;
        push(result, sum % 10);
